mapper.delete:
DELETE FROM cat_user_role
WHERE
    user_id = #{userId}
    AND role_id = #{roleId}

DELETE FROM cat_org_user
WHERE
    user_id = #{userId}
  AND org_id = #{orgId}

mapper.select:
SELECT DISTINCT cu.* FROM cat_user cu
LEFT JOIN cat_user_role cur ON cu.id = cur.user_id
LEFT JOIN cat_org_user cou ON cu.id = cou.org_id
where cu.deleted = '0'
AND ( cu.username LIKE CONCAT('%',#{param.search},'%') OR cu.nickname LIKE CONCAT('%',#{param.search},'%') OR cu.id LIKE CONCAT('%',#{param.search},'%') )
AND cur.role_id = #{param.roleId}
AND cou.org_id = #{param.orgId}
AND cu.type = #{param.type}

SELECT COUNT(1)
FROM cat_user_role
where role_id = #{roleId}
